import React from "react";
import logo from "./logo.png";

export default function Logo({ size = "md" }) {
  const s = { sm: [28, 16], md: [36, 20], lg: [44, 24] }[size];

  return <img src={logo} alt="Logo" width={s[0]} height={s[0]} />;
}
